 29	export const HEADERS = 'headers';
 30	export const URI = 'uri';
 31	export const SCHEME = 'scheme';
 32	export const METHOD = 'method';
 33	export const AUTHORITY = 'authority';
 34	
 35	const matchOptions: string[] = [HEADERS, URI, SCHEME, METHOD, AUTHORITY];
 36	
 37	export const EXACT = 'exact';
 38	export const PREFIX = 'prefix';
 39	export const REGEX = 'regex';
 40	
 41	// Pseudo operator
 42	export const PRESENCE = 'presents';
 43	export const ANYTHING = '{}';
 44	
 45	const opOptions: string[] = [EXACT, PREFIX, REGEX];
 46	
 47	const placeholderText = {
 48	  [HEADERS]: 'Header value...',
 49	  [URI]: 'Uri value...',
 50	  [SCHEME]: 'Scheme value...',
 51	  [METHOD]: 'Method value...',
 52	  [AUTHORITY]: 'Authority value...'
 53	};
 54	
 55	export const MatchBuilder: React.FC<MatchBuilderProps> = (props: MatchBuilderProps) => {
 56	  const [isMatchDropdown, setIsMatchDropdown] = React.useState<boolean>(false);
 57	  const [isOperatorDropdown, setIsOperatorDropdown] = React.useState<boolean>(false);
 58	  const renderOpOptions: string[] = props.category === HEADERS ? [PRESENCE, ...opOptions] : opOptions;
 59	
 60	  return (
 61	    <InputGroup>
 62	      <InputGroupItem>
 63	        <Dropdown
 64	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 65	            <MenuToggle
 66	              ref={toggleRef}
 67	              onClick={() => setIsMatchDropdown(!isMatchDropdown)}
 68	              data-test={'requestmatching-header-toggle'}
 69	              isExpanded={isMatchDropdown}
 70	            >
 71	              {props.category}
 72	            </MenuToggle>
 73	          )}
 74	          isOpen={isMatchDropdown}
 75	          onOpenChange={(isOpen: boolean) => setIsMatchDropdown(isOpen)}
 76	        >
 77	          <DropdownList>
 78	            {matchOptions.map((mode, index) => (
 79	              <DropdownItem
 80	                key={`${mode}_${index}`}
 81	                value={mode}
 82	                component="button"
 83	                onClick={() => {
 84	                  props.onSelectCategory(mode);
 85	                  setIsMatchDropdown(!isMatchDropdown);
 86	                }}
 87	                data-test={`requestmatching-header-${mode}`}
 88	              >
 89	                {mode}
 90	              </DropdownItem>
 91	            ))}
 92	          </DropdownList>
 93	        </Dropdown>
 94	      </InputGroupItem>
 95	
 96	      {props.category === HEADERS && (
 97	        <TextInput
 98	          id="header-name-id"
 99	          value={props.headerName}
100	          onChange={(_, value) => props.onHeaderNameChange(value)}
101	          placeholder="Header name..."
102	        />
103	      )}
104	
105	      <InputGroupItem>
106	        <Dropdown
107	          toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
108	            <MenuToggle
109	              ref={toggleRef}
110	              onClick={() => setIsOperatorDropdown(!isOperatorDropdown)}
111	              data-test={'requestmatching-match-toggle'}
112	              isExpanded={isOperatorDropdown}
113	            >
114	              {props.operator}
115	            </MenuToggle>
116	          )}
117	          isOpen={isOperatorDropdown}
118	          onOpenChange={(isOpen: boolean) => setIsOperatorDropdown(isOpen)}
119	        >
120	          <DropdownList>
121	            {renderOpOptions.map((op, index) => (
122	              <DropdownItem
123	                key={`${op}_${index}`}
124	                value={op}
125	                component="button"
126	                onClick={() => {
127	                  props.onSelectOperator(op);
128	                  setIsOperatorDropdown(!isOperatorDropdown);
129	                }}
130	                data-test={`requestmatching-match-${op}`}
131	              >
132	                {op}
133	              </DropdownItem>
134	            ))}
135	          </DropdownList>
136	        </Dropdown>
137	      </InputGroupItem>
138	
139	      {props.operator !== PRESENCE && (
140	        <TextInput
141	          id="match-value-id"
142	          value={props.matchValue}
143	          onChange={(_, value) => props.onMatchValueChange(value)}
144	          placeholder={placeholderText[props.category]}
145	        />
146	      )}
147	
148	      <InputGroupItem>
149	        <Button
150	          variant={ButtonVariant.secondary}
151	          isDisabled={!props.isValid}
152	          onClick={props.onAddMatch}
153	          data-test="add-match"
154	        >
155	          {t('Add Match')}
156	        </Button>
157	      </InputGroupItem>
158	    </InputGroup>
159	  );
160	};

